const staticData = $getWorkflowStaticData('global');
const sinceToken = staticData.sinceToken || '';
const homeserver = $env.MATRIX_HOMESERVER;
const todoRoom = $env.MATRIX_ROOM_TODO;
const botToken = $env.MATRIX_BOT_TOKEN;

if (!homeserver || !todoRoom || !botToken) {
  return [];
}

const filter = JSON.stringify({
  room: {
    rooms: [todoRoom],
    timeline: { types: ['m.room.message'], limit: 20 }
  },
  presence: { types: [] },
  account_data: { types: [] }
});

// timeout=8000: long-polling, returns immediately when new events arrive
let syncUrl = `${homeserver}/_matrix/client/v3/sync?timeout=8000&filter=${encodeURIComponent(filter)}`;
if (sinceToken) {
  syncUrl += `&since=${encodeURIComponent(sinceToken)}`;
}

return [{ json: { syncUrl, isFirstRun: !sinceToken, todoRoom } }];

const staticData = $getWorkflowStaticData('global');
const syncResp = $input.first().json;
const prevData = $('\u51c6\u5907\u540c\u6b65').first().json;
const isFirstRun = prevData.isFirstRun;
const todoRoom = prevData.todoRoom;

if (syncResp.next_batch) {
  staticData.sinceToken = syncResp.next_batch;
}

if (isFirstRun || syncResp.errcode) {
  return [];
}

const results = [];
const joinedRooms = syncResp.rooms?.join || {};

for (const [roomId, roomData] of Object.entries(joinedRooms)) {
  if (roomId !== todoRoom) continue;
  const events = roomData.timeline?.events || [];

  for (const event of events) {
    if (event.type !== 'm.room.message') continue;
    if (event.sender && event.sender.startsWith('@kb-bot:')) continue;

    const body = (event.content?.body || '').trim();
    if (!body.startsWith('!') && !body.startsWith('\uff01')) continue;

    const parts = body.substring(1).trim().split(/\s+/);
    const cmd = parts[0];
    const args = parts.slice(1).join(' ');
    let result = null;

    switch(cmd) {
      case '\u5f85\u529e': case '\u5217\u8868': case '\u5f85\u529e\u5217\u8868':
      case '\u67e5\u8be2': case '\u67e5\u770b':
        result = { action: 'list' };
        break;
      case '\u4eca\u65e5': case '\u4eca\u5929':
        result = { action: 'list', filter: 'today' };
        break;
      case '\u903e\u671f':
        result = { action: 'list', filter: 'overdue' };
        break;
      case '\u65b0\u589e': case '\u6dfb\u52a0':
        if (args) {
          let priority = 3;
          let dueDate = '';
          let remaining = args;
          for (let i = 0; i < 2; i++) {
            const pMatch = remaining.match(/^P(\d)\s+([\s\S]*)/);
            if (pMatch) { priority = parseInt(pMatch[1]); remaining = pMatch[2]; continue; }
            const dFull = remaining.match(/^D(\d{4}-\d{1,2}-\d{1,2})\s+([\s\S]*)/);
            if (dFull) { dueDate = dFull[1]; remaining = dFull[2]; continue; }
            const dShort = remaining.match(/^D(\d{1,2})\/(\d{1,2})\s+([\s\S]*)/);
            if (dShort) {
              const y = new Date().getFullYear();
              dueDate = `${y}-${dShort[1].padStart(2,'0')}-${dShort[2].padStart(2,'0')}`;
              remaining = dShort[3]; continue;
            }
            break;
          }
          if (remaining.trim()) {
            result = { action: 'add', text: remaining.trim(), priority, dueDate };
          }
        }
        break;
      case '\u5b8c\u6210':
        if (args) result = { action: 'done', memo_name: `memos/${args}` };
        break;
      case '\u5220\u9664':
        if (args) result = { action: 'delete', memo_name: `memos/${args}` };
        break;
      case '\u4fee\u6539': {
        const modParts = args.split(/\s+/);
        if (modParts.length >= 2) {
          result = { action: 'modify', memo_name: `memos/${modParts[0]}`, text: modParts.slice(1).join(' ') };
        }
        break;
      }
      case '\u5e2e\u52a9': case 'help':
        result = { action: 'help' };
        break;
    }

    if (result) {
      result.sender = event.sender;
      results.push(result);
    }
  }
}

return results.length > 0 ? results.map(r => ({ json: r })) : [];

const response = $input.first().json;
const command = $('\u5e2e\u52a9\u6307\u4ee4?').item.json;
const action = command.action;
const filter = command.filter || '';

let message = '';

if (response.success === false || response.error) {
  message = `\u274c \u64cd\u4f5c\u5931\u8d25: ${response.error || '\u672a\u77e5\u9519\u8bef'}`;
} else {
  switch(action) {
    case 'list': {
      let memos = response.memos || [];
      const now = new Date();
      const todayStr = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;

      // Apply filter
      if (filter === 'today') {
        memos = memos.filter(m => {
          const d = (m.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          return d && d[1] === todayStr;
        });
      } else if (filter === 'overdue') {
        memos = memos.filter(m => {
          const d = (m.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          return d && d[1] < todayStr;
        });
      }

      const filterLabel = filter === 'today' ? '\u4eca\u65e5\u5230\u671f' : filter === 'overdue' ? '\u903e\u671f' : '\u5f85\u529e\u5217\u8868';

      if (memos.length === 0) {
        const emptyMsg = filter === 'today' ? '\u4eca\u65e5\u6ca1\u6709\u5230\u671f\u4e8b\u9879' : filter === 'overdue' ? '\u6ca1\u6709\u903e\u671f\u4e8b\u9879' : '\u5f53\u524d\u6ca1\u6709\u5f85\u529e\u4e8b\u9879';
        message = `\ud83d\udcdd ${emptyMsg}`;
      } else {
        // Sort: overdue first, then by due date asc, then priority
        memos.sort((a, b) => {
          const dA = (a.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          const dB = (b.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          const dateA = dA ? dA[1] : '9999-99-99';
          const dateB = dB ? dB[1] : '9999-99-99';
          const overA = dA && dA[1] < todayStr ? 0 : 1;
          const overB = dB && dB[1] < todayStr ? 0 : 1;
          if (overA !== overB) return overA - overB;
          if (dateA !== dateB) return dateA.localeCompare(dateB);
          const pA = parseInt((a.content?.match(/#P(\d)/) || [])[1] || '3');
          const pB = parseInt((b.content?.match(/#P(\d)/) || [])[1] || '3');
          return pA - pB;
        });

        const lines = [`\ud83d\udcdd ${filterLabel} (${memos.length}\u9879):`];
        memos.forEach((memo, i) => {
          const content = memo.content || '';
          const text = content.replace(/#\S+/g, '').trim();
          const id = (memo.name || '').replace('memos/', '');
          const priority = (content.match(/#P(\d)/) || [])[1] || '3';
          const pEmoji = priority === '1' ? '\ud83d\udd34' : priority === '2' ? '\ud83d\udfe1' : '\u26aa';
          const dueMatch = content.match(/#D:(\d{4})-(\d{2})-(\d{2})/);
          let dateStr = '';
          if (dueMatch) {
            const isOverdue = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}` < todayStr;
            const isToday = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}` === todayStr;
            dateStr = isOverdue ? ` \u26a0\ufe0f${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}(\u903e\u671f)` : isToday ? ` \ud83d\udcc5\u4eca\u65e5` : ` \ud83d\udcc5${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}`;
          }
          lines.push(`${pEmoji} ${i+1}. [#${id}] P${priority}${dateStr} ${text}`);
        });
        message = lines.join('\n');
      }
      break;
    }
    case 'add': {
      let extra = '';
      if (command.dueDate) {
        const dp = command.dueDate.split('-');
        extra = ` (\ud83d\udcc5${parseInt(dp[1])}/${parseInt(dp[2])})`;
      }
      message = `\u2795 \u5df2\u6dfb\u52a0\u5f85\u529e: ${command.text}${extra}`;
      break;
    }
    case 'done':
      message = `\u2705 \u5df2\u5b8c\u6210: ${(command.memo_name || '').replace('memos/', '#')}`;
      break;
    case 'delete':
      message = `\ud83d\uddd1\ufe0f \u5df2\u5220\u9664: ${(command.memo_name || '').replace('memos/', '#')}`;
      break;
    case 'modify':
      message = `\u270f\ufe0f \u5df2\u4fee\u6539: ${command.text}`;
      break;
    default:
      message = `\u2753 \u672a\u77e5\u64cd\u4f5c: ${action}`;
  }
}

return [{ json: { room: 'todo', message } }];

const data = $input.first().json;
const memos = data.memos || [];

const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const todayStr = dateStr;

let message = '';

if (memos.length === 0) {
  message = `\ud83c\udf05 \u65e9\u5b89! ${dateStr}\n\n\u2728 \u4eca\u65e5\u6ca1\u6709\u5f85\u529e\u4e8b\u9879\uff0c\u4eab\u53d7\u7f8e\u597d\u7684\u4e00\u5929!`;
} else {
  const overdue = [];
  const dueToday = [];
  const upcoming = [];
  const noDue = [];

  memos.forEach(memo => {
    const content = memo.content || '';
    const dueMatch = content.match(/#D:(\d{4}-\d{2}-\d{2})/);
    if (dueMatch) {
      if (dueMatch[1] < todayStr) overdue.push(memo);
      else if (dueMatch[1] === todayStr) dueToday.push(memo);
      else upcoming.push(memo);
    } else {
      noDue.push(memo);
    }
  });

  const sortByPriority = (a, b) => {
    const pA = parseInt((a.content?.match(/#P(\d)/) || [])[1] || '3');
    const pB = parseInt((b.content?.match(/#P(\d)/) || [])[1] || '3');
    return pA - pB;
  };
  overdue.sort(sortByPriority);
  dueToday.sort(sortByPriority);
  upcoming.sort((a, b) => {
    const dA = (a.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/)[1];
    const dB = (b.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/)[1];
    return dA === dB ? sortByPriority(a, b) : dA.localeCompare(dB);
  });
  noDue.sort(sortByPriority);

  const lines = [`\ud83c\udf05 \u65e9\u5b89! ${dateStr}`, '', `\ud83d\udcdd \u5f85\u529e\u603b\u89c8 (${memos.length}\u9879):`];

  const formatMemo = (memo, idx) => {
    const content = memo.content || '';
    const text = content.replace(/#\S+/g, '').trim();
    const id = (memo.name || '').replace('memos/', '');
    const priority = (content.match(/#P(\d)/) || [])[1] || '3';
    const pEmoji = priority === '1' ? '\ud83d\udd34' : priority === '2' ? '\ud83d\udfe1' : '\u26aa';
    const dueMatch = content.match(/#D:(\d{4})-(\d{2})-(\d{2})/);
    let dateTag = '';
    if (dueMatch) {
      const ds = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}`;
      if (ds < todayStr) dateTag = ` \u26a0\ufe0f${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}(\u903e\u671f)`;
      else if (ds === todayStr) dateTag = ` \ud83d\udcc5\u4eca\u65e5`;
      else dateTag = ` \ud83d\udcc5${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}`;
    }
    return `${pEmoji} ${idx}. [#${id}]${dateTag} ${text}`;
  };

  let idx = 1;
  if (overdue.length > 0) {
    lines.push(`\n\u26a0\ufe0f \u903e\u671f (${overdue.length}\u9879):`);
    overdue.forEach(m => { lines.push(formatMemo(m, idx++)); });
  }
  if (dueToday.length > 0) {
    lines.push(`\n\ud83d\udcc5 \u4eca\u65e5\u5230\u671f (${dueToday.length}\u9879):`);
    dueToday.forEach(m => { lines.push(formatMemo(m, idx++)); });
  }
  if (upcoming.length > 0 || noDue.length > 0) {
    const rest = [...upcoming, ...noDue];
    lines.push(`\n\ud83d\udccc \u5176\u4ed6 (${rest.length}\u9879):`);
    rest.forEach(m => { lines.push(formatMemo(m, idx++)); });
  }

  lines.push('', '\u53d1\u9001 !\u5e2e\u52a9 \u67e5\u770b\u6307\u4ee4\u7528\u6cd5');
  message = lines.join('\n');
}

return [{ json: { room: 'todo', message } }];
